const body = $json.body ?? $json;
const sessionId = String(body.session_id ?? '').trim();
if (!sessionId) {
  throw new Error('session_id is required');
}
const limitRaw = Number(body.limit ?? 12);
const limit = Number.isFinite(limitRaw) ? Math.max(1, Math.min(50, Math.trunc(limitRaw))) : 12;
const tokenExpected = $env.AGENT_WORKFLOW_TOKEN || '';
const tokenProvided = String(body.token ?? '');
if (tokenExpected && tokenProvided !== tokenExpected) {
  throw new Error('invalid token');
}
const identRe = /^[A-Za-z_][A-Za-z0-9_]{0,62}$/;
const memorySchema = String($env.AGENT_MEMORY_SCHEMA || 'agent').trim();
const memoryTable = String($env.AGENT_MEMORY_TABLE || 'agent_memory_messages').trim();
if (!identRe.test(memorySchema)) {
  throw new Error('invalid AGENT_MEMORY_SCHEMA');
}
if (!identRe.test(memoryTable)) {
  throw new Error('invalid AGENT_MEMORY_TABLE');
}
return [{
  json: {
    session_id: sessionId,
    session_id_sql: sessionId.replace(/'/g, "''"),
    memory_schema_sql: memorySchema,
    memory_table_sql: memoryTable,
    limit
  }
}];

parameters.query:
SELECT role, message, metadata, created_at
FROM {{$json.memory_schema_sql}}.{{$json.memory_table_sql}}
WHERE session_id = '{{$json.session_id_sql}}'
ORDER BY created_at DESC
LIMIT {{$json.limit}};

